(function () {
    "use strict";

    var OLLAMA = "http://127.0.0.1:11434";
    var DEFAULT_VISION_MODEL = "llama3.2-vision";
    var DEFAULT_CHAT_MODEL = "llama3.2";
    var TRANSLATE_PROMPT =
        "Este é um mangá. Extrai todo o texto visível nos balões de fala, caixas de narração e onomatopeias." +
        " Traduz para Português de Portugal (PT-PT)." +
        " Mantém a ordem de leitura japonesa (direita para esquerda, cima para baixo)." +
        " Responde APENAS com as traduções numeradas, sem explicações." +
        " Formato:\n[1]: texto traduzido\n[2]: texto traduzido\n...";

    $ui.register(function (ctx) {

        // ── Listar todos os modelos ───────────────────────────────────
        ctx.channel.on("ollama:models", function () {
            try {
                var r = fetch(OLLAMA + "/api/tags");
                var d = r.json();
                var all = (d.models || []).map(function (m) { return m.name; });
                var vision = all.filter(function (n) {
                    var l = n.toLowerCase();
                    return l.indexOf("vision") !== -1 || l.indexOf("llava") !== -1 ||
                           l.indexOf("minicpm") !== -1 || l.indexOf("moondream") !== -1 || l.indexOf("gemma3") !== -1;
                });
                return { ok: true, all: all, vision: vision.length > 0 ? vision : all };
            } catch (e) {
                return { ok: false, all: [DEFAULT_VISION_MODEL, DEFAULT_CHAT_MODEL], vision: [DEFAULT_VISION_MODEL] };
            }
        });

        // ── Traduzir página (imagem → base64 → Ollama vision) ────────
        ctx.channel.on("ollama:translate", function (data) {
            try {
                var headers = {};
                if (data.referer) headers["Referer"] = data.referer;
                var imgResp = fetch(data.url, { headers: headers });
                if (!imgResp.ok) return { ok: false, error: "HTTP " + imgResp.status + " ao descarregar imagem" };

                var bytes = new Uint8Array(imgResp.arrayBuffer());
                var bin = "";
                for (var i = 0; i < bytes.byteLength; i++) bin += String.fromCharCode(bytes[i]);
                var b64 = btoa(bin);

                var resp = fetch(OLLAMA + "/api/generate", {
                    method: "POST",
                    headers: { "Content-Type": "application/json" },
                    body: JSON.stringify({
                        model: data.model || DEFAULT_VISION_MODEL,
                        prompt: TRANSLATE_PROMPT,
                        images: [b64],
                        stream: false,
                        options: { temperature: 0.1, num_predict: 768 }
                    })
                });
                if (!resp.ok) return { ok: false, error: "Ollama HTTP " + resp.status };
                var text = (resp.json().response || "").trim();
                if (!text) return { ok: false, error: "Sem resposta do modelo. Verifica se suporta visão." };
                return { ok: true, text: text };
            } catch (e) {
                return { ok: false, error: String(e) };
            }
        });

        // ── Chat com contexto (perguntas, refinamento, verificação) ──
        ctx.channel.on("ollama:chat", function (data) {
            try {
                var messages = data.messages || [];
                var resp = fetch(OLLAMA + "/api/chat", {
                    method: "POST",
                    headers: { "Content-Type": "application/json" },
                    body: JSON.stringify({
                        model: data.model || DEFAULT_CHAT_MODEL,
                        messages: messages,
                        stream: false,
                        options: { temperature: 0.4, num_predict: 1024 }
                    })
                });
                if (!resp.ok) return { ok: false, error: "Ollama HTTP " + resp.status };
                var msg = resp.json().message || {};
                var text = (msg.content || "").trim();
                if (!text) return { ok: false, error: "Sem resposta do modelo." };
                return { ok: true, text: text };
            } catch (e) {
                return { ok: false, error: String(e) };
            }
        });

        // ── Tray ─────────────────────────────────────────────────────
        ctx.tray.add({
            id: "manga-translator",
            label: "Tradutor Mangá",
            icon: "language",
            onClick: function () { ctx.panels.open("translator-panel"); }
        });

        // ── Panel ────────────────────────────────────────────────────
        ctx.panels.register({
            id: "translator-panel",
            title: "Tradutor de Mangá",
            width: "400px",
            render: function (panel) {

                var SYSTEM_PROMPT =
                    "És um assistente especialista em mangá e anime. " +
                    "Ajudas a traduzir, verificar e melhorar traduções de mangá para Português de Portugal (PT-PT). " +
                    "Quando o utilizador partilha uma tradução, podes: corrigir erros, melhorar naturalidade, " +
                    "explicar referências culturais, identificar personagens, e contextualizar o enredo. " +
                    "Responde sempre em PT-PT de forma concisa e direta.";

                var state = {
                    // Tradução
                    tab: "translate",
                    imageUrl: "",
                    visionModel: ctx.store.get("t:visionModel") || DEFAULT_VISION_MODEL,
                    chatModel: ctx.store.get("t:chatModel") || DEFAULT_CHAT_MODEL,
                    allModels: [DEFAULT_VISION_MODEL, DEFAULT_CHAT_MODEL],
                    visionModels: [DEFAULT_VISION_MODEL],
                    translating: false,
                    translation: "",
                    error: "",
                    history: ctx.store.get("t:history") || [],
                    // Chat
                    chatInput: "",
                    chatMessages: [],  // { role, content }
                    chatLoading: false,
                    chatError: "",
                    mangaTitle: ctx.store.get("t:title") || ""
                };

                // Carregar modelos
                panel.channel.emit("ollama:models", {}, function (resp) {
                    if (resp && resp.ok) {
                        state.allModels = resp.all;
                        state.visionModels = resp.vision;
                        if (resp.vision.indexOf(state.visionModel) === -1) state.visionModel = resp.vision[0];
                        if (resp.all.indexOf(state.chatModel) === -1) state.chatModel = resp.all[0];
                        panel.update(state);
                    }
                });

                function captureCurrentPage() {
                    var selectors = [".manga-reader-page img","[data-page] img",".page-container img",".reader-image","img[data-src]",".reader img"];
                    var found = null, centerY = window.innerHeight / 2, closest = Infinity;
                    for (var s = 0; s < selectors.length; s++) {
                        var imgs = document.querySelectorAll(selectors[s]);
                        if (!imgs || !imgs.length) continue;
                        for (var i = 0; i < imgs.length; i++) {
                            var rect = imgs[i].getBoundingClientRect();
                            if (rect.width < 100) continue;
                            var d = Math.abs(rect.top + rect.height / 2 - centerY);
                            if (d < closest) { closest = d; found = imgs[i]; }
                        }
                        if (found) break;
                    }
                    if (found) { state.imageUrl = found.src || found.getAttribute("data-src") || ""; state.error = ""; }
                    else state.error = "Não detetei a página. Cola o URL manualmente.";
                    panel.update(state);
                }

                function translate() {
                    if (!state.imageUrl) { state.error = "Insere ou captura o URL primeiro."; panel.update(state); return; }
                    state.translating = true; state.translation = ""; state.error = "";
                    panel.update(state);
                    panel.channel.emit("ollama:translate", { url: state.imageUrl, model: state.visionModel, referer: window.location.href }, function (resp) {
                        state.translating = false;
                        if (resp && resp.ok) {
                            state.translation = resp.text;
                            state.history.unshift({ url: state.imageUrl, text: resp.text, ts: new Date().toLocaleTimeString("pt-PT") });
                            if (state.history.length > 8) state.history.pop();
                            ctx.store.set("t:history", state.history);
                        } else {
                            state.error = (resp && resp.error) || "Erro desconhecido";
                        }
                        panel.update(state);
                    });
                }

                function buildMessages(userMsg) {
                    var msgs = [{ role: "system", content: SYSTEM_PROMPT }];
                    // Injetar contexto se existir
                    if (state.mangaTitle || state.translation) {
                        var ctx_msg = "Contexto atual:";
                        if (state.mangaTitle) ctx_msg += "\nMangá: " + state.mangaTitle;
                        if (state.translation) ctx_msg += "\nTradução da página atual:\n" + state.translation;
                        msgs.push({ role: "user", content: ctx_msg });
                        msgs.push({ role: "assistant", content: "Entendido, tenho o contexto. Como posso ajudar?" });
                    }
                    // Histórico de chat (últimas 6 mensagens)
                    var hist = state.chatMessages.slice(-6);
                    for (var i = 0; i < hist.length; i++) msgs.push(hist[i]);
                    msgs.push({ role: "user", content: userMsg });
                    return msgs;
                }

                function sendChat(msg) {
                    if (!msg) return;
                    state.chatMessages.push({ role: "user", content: msg });
                    state.chatInput = "";
                    state.chatLoading = true;
                    state.chatError = "";
                    panel.update(state);

                    panel.channel.emit("ollama:chat", {
                        model: state.chatModel,
                        messages: buildMessages(msg)
                    }, function (resp) {
                        state.chatLoading = false;
                        if (resp && resp.ok) {
                            state.chatMessages.push({ role: "assistant", content: resp.text });
                        } else {
                            state.chatError = (resp && resp.error) || "Erro";
                        }
                        panel.update(state);
                    });
                }

                function quickAction(action) {
                    var prompts = {
                        refine: "Melhora a naturalidade desta tradução em PT-PT. Corrige erros e torna o diálogo mais natural. Mantém o formato [1]: [2]: etc.",
                        verify: "Verifica esta tradução. Identifica erros de tradução, problemas de contexto, ou frases que não fazem sentido. Sê específico.",
                        characters: "Com base nesta tradução, quem são as personagens mencionadas? O que podes deduzir sobre elas e a situação?",
                        explain: "Explica referências culturais japonesas, gírias ou expressões específicas que apareçam nesta tradução."
                    };
                    if (!state.translation && action !== "refine" && action !== "verify") {
                        state.chatError = "Traduz uma página primeiro para usar esta função.";
                        panel.update(state);
                        return;
                    }
                    sendChat(prompts[action]);
                    state.tab = "chat";
                    panel.update(state);
                }

                return {
                    state: state,
                    onTab: function (t) { state.tab = t; state.chatError = ""; panel.update(state); },
                    onVisionModel: function (v) { state.visionModel = v; ctx.store.set("t:visionModel", v); panel.update(state); },
                    onChatModel: function (v) { state.chatModel = v; ctx.store.set("t:chatModel", v); panel.update(state); },
                    onUrl: function (v) { state.imageUrl = v; panel.update(state); },
                    onTitle: function (v) { state.mangaTitle = v; ctx.store.set("t:title", v); panel.update(state); },
                    onCapture: captureCurrentPage,
                    onTranslate: translate,
                    onChatInput: function (v) { state.chatInput = v; panel.update(state); },
                    onChatSend: function () { sendChat(state.chatInput.trim()); },
                    onChatKey: function (e) { if (e.key === "Enter" && !e.shiftKey) { e.preventDefault(); sendChat(state.chatInput.trim()); } },
                    onQuick: quickAction,
                    onClearChat: function () { state.chatMessages = []; state.chatError = ""; panel.update(state); },
                    onClearHistory: function () { state.history = []; ctx.store.set("t:history", []); panel.update(state); },
                    onHistorySelect: function (entry) { state.imageUrl = entry.url; state.translation = entry.text; state.error = ""; panel.update(state); }
                };
            },

            template: function (props) {
                var s = props.state;

                var BG      = "#0a0a16";
                var SURF    = "#11111e";
                var CARD    = "#15152a";
                var BORDER  = "#222238";
                var PURPLE  = "#7c3aed";
                var PURPLE_DIM = "#3d1c7a";
                var TEXT    = "#e0e0f0";
                var MUTED   = "#55557a";
                var ERR     = "#f87171";
                var ERR_BG  = "#1e0a0a";
                var OK_BG   = "#0a1a10";
                var OK_TXT  = "#86efac";
                var ACCENT  = "#a78bfa";

                var e = React.createElement;

                // ── Tab bar ──────────────────────────────────────────
                function tabBtn(id, label, active) {
                    return e("button", {
                        key: id, onClick: function () { props.onTab(id); },
                        style: {
                            flex: 1, padding: "9px 0", fontSize: "12px", fontWeight: active ? 700 : 400,
                            background: active ? PURPLE : "transparent",
                            color: active ? "#fff" : MUTED,
                            border: "none", borderBottom: active ? "2px solid " + ACCENT : "2px solid " + BORDER,
                            cursor: "pointer"
                        }
                    }, label);
                }

                // ── Quick action buttons ──────────────────────────────
                function quickBtn(id, label, emoji) {
                    return e("button", {
                        key: id, onClick: function () { props.onQuick(id); },
                        title: label,
                        style: {
                            flex: 1, padding: "6px 4px", fontSize: "10px", fontWeight: 600,
                            background: CARD, color: ACCENT,
                            border: "1px solid " + BORDER, borderRadius: "6px",
                            cursor: "pointer", textAlign: "center", lineHeight: "1.3"
                        }
                    }, e("div", null, emoji), e("div", null, label));
                }

                // ── TAB: Traduzir ─────────────────────────────────────
                var translateTab = s.tab === "translate" ? e("div", { style: { padding: "12px 14px" } },

                    // Título do mangá
                    e("input", {
                        type: "text", value: s.mangaTitle,
                        placeholder: "Título do mangá (contexto para o chat)...",
                        onChange: function (ev) { props.onTitle(ev.target.value); },
                        style: { width: "100%", padding: "6px 10px", background: SURF, color: TEXT, border: "1px solid " + BORDER, borderRadius: "6px", fontSize: "12px", boxSizing: "border-box", marginBottom: "10px" }
                    }),

                    // Modelo de visão
                    e("div", { style: { display: "flex", alignItems: "center", gap: "8px", marginBottom: "10px" } },
                        e("span", { style: { fontSize: "11px", color: MUTED, whiteSpace: "nowrap" } }, "Modelo visão"),
                        e("select", {
                            value: s.visionModel, onChange: function (ev) { props.onVisionModel(ev.target.value); },
                            style: { flex: 1, padding: "5px 8px", background: SURF, color: TEXT, border: "1px solid " + BORDER, borderRadius: "6px", fontSize: "12px" }
                        }, s.visionModels.map(function (m) { return e("option", { key: m, value: m }, m); }))
                    ),

                    // URL
                    e("input", {
                        type: "text", value: s.imageUrl,
                        placeholder: "URL da imagem...",
                        onChange: function (ev) { props.onUrl(ev.target.value); },
                        style: { width: "100%", padding: "6px 10px", background: SURF, color: TEXT, border: "1px solid " + BORDER, borderRadius: "6px", fontSize: "12px", boxSizing: "border-box", marginBottom: "8px" }
                    }),

                    // Botões capturar + traduzir
                    e("div", { style: { display: "flex", gap: "6px", marginBottom: "10px" } },
                        e("button", { onClick: props.onCapture, style: { flex: 1, padding: "7px", background: CARD, color: TEXT, border: "1px solid " + BORDER, borderRadius: "6px", cursor: "pointer", fontSize: "11px" } }, "📷 Capturar"),
                        e("button", {
                            onClick: props.onTranslate, disabled: s.translating,
                            style: { flex: 2, padding: "7px", background: s.translating ? BORDER : PURPLE, color: s.translating ? MUTED : "#fff", border: "none", borderRadius: "6px", cursor: s.translating ? "not-allowed" : "pointer", fontWeight: 700, fontSize: "11px" }
                        }, s.translating ? "A traduzir..." : "🌐 Traduzir")
                    ),

                    // Erro
                    s.error ? e("div", { style: { padding: "8px 10px", background: ERR_BG, color: ERR, borderRadius: "6px", marginBottom: "8px", fontSize: "11px" } }, "⚠ " + s.error) : null,

                    // Tradução
                    s.translation ? e("div", { style: { marginBottom: "12px" } },
                        e("div", { style: { display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: "5px" } },
                            e("span", { style: { fontSize: "10px", color: MUTED, textTransform: "uppercase", letterSpacing: "0.5px" } }, "Tradução"),
                            e("button", {
                                onClick: function () { props.onTab("chat"); },
                                style: { fontSize: "10px", padding: "2px 8px", background: PURPLE_DIM, color: ACCENT, border: "1px solid " + PURPLE, borderRadius: "4px", cursor: "pointer" }
                            }, "💬 Discutir no chat →")
                        ),
                        e("div", {
                            style: { padding: "10px", background: OK_BG, border: "1px solid #1a3a1a", borderRadius: "6px", fontSize: "12px", lineHeight: "1.8", color: OK_TXT, whiteSpace: "pre-wrap", maxHeight: "260px", overflowY: "auto" }
                        }, s.translation)
                    ) : (!s.error && !s.translating ? e("div", { style: { textAlign: "center", color: MUTED, padding: "24px 0", fontSize: "12px" } }, "Captura ou cola um URL e clica em Traduzir") : null),

                    // Histórico
                    s.history.length > 0 ? e("div", null,
                        e("div", { style: { display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: "5px" } },
                            e("span", { style: { fontSize: "10px", color: MUTED, textTransform: "uppercase", letterSpacing: "0.5px" } }, "Histórico"),
                            e("button", { onClick: props.onClearHistory, style: { fontSize: "10px", color: MUTED, background: "none", border: "none", cursor: "pointer" } }, "limpar")
                        ),
                        e("div", { style: { display: "flex", flexDirection: "column", gap: "3px" } },
                            s.history.map(function (entry, i) {
                                return e("div", {
                                    key: i, onClick: function () { props.onHistorySelect(entry); },
                                    style: { padding: "7px 10px", background: CARD, border: "1px solid " + BORDER, borderRadius: "6px", cursor: "pointer", fontSize: "11px" }
                                },
                                    e("div", { style: { color: MUTED, marginBottom: "2px" } }, entry.ts),
                                    e("div", { style: { color: TEXT, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" } }, entry.text.substring(0, 55) + (entry.text.length > 55 ? "..." : ""))
                                );
                            })
                        )
                    ) : null

                ) : null;

                // ── TAB: Chat ─────────────────────────────────────────
                var chatTab = s.tab === "chat" ? e("div", { style: { padding: "12px 14px", display: "flex", flexDirection: "column" } },

                    // Modelo de chat
                    e("div", { style: { display: "flex", alignItems: "center", gap: "8px", marginBottom: "10px" } },
                        e("span", { style: { fontSize: "11px", color: MUTED, whiteSpace: "nowrap" } }, "Modelo chat"),
                        e("select", {
                            value: s.chatModel, onChange: function (ev) { props.onChatModel(ev.target.value); },
                            style: { flex: 1, padding: "5px 8px", background: SURF, color: TEXT, border: "1px solid " + BORDER, borderRadius: "6px", fontSize: "12px" }
                        }, s.allModels.map(function (m) { return e("option", { key: m, value: m }, m); }))
                    ),

                    // Ações rápidas
                    e("div", { style: { display: "flex", gap: "5px", marginBottom: "10px" } },
                        quickBtn("refine",     "Aprimorar",    "✨"),
                        quickBtn("verify",     "Verificar",    "🔍"),
                        quickBtn("characters", "Personagens",  "👤"),
                        quickBtn("explain",    "Explicar",     "📖")
                    ),

                    // Contexto ativo
                    (s.translation || s.mangaTitle) ? e("div", {
                        style: { padding: "6px 10px", background: CARD, border: "1px solid " + BORDER, borderRadius: "6px", fontSize: "10px", color: MUTED, marginBottom: "8px" }
                    },
                        "📄 Contexto: ",
                        s.mangaTitle ? e("span", { style: { color: ACCENT } }, s.mangaTitle + " ") : null,
                        s.translation ? e("span", null, "· tradução carregada") : null
                    ) : e("div", {
                        style: { padding: "6px 10px", background: ERR_BG, border: "1px solid " + BORDER, borderRadius: "6px", fontSize: "10px", color: MUTED, marginBottom: "8px" }
                    }, "⚠ Sem contexto — traduz uma página primeiro para melhores resultados"),

                    // Histórico de mensagens
                    e("div", {
                        style: { minHeight: "200px", maxHeight: "340px", overflowY: "auto", display: "flex", flexDirection: "column", gap: "8px", marginBottom: "10px" }
                    },
                        s.chatMessages.length === 0 ? e("div", { style: { color: MUTED, fontSize: "12px", textAlign: "center", padding: "20px 0" } },
                            "Usa os botões acima ou escreve uma pergunta.",
                            e("br"), e("br"),
                            e("span", { style: { fontSize: "11px" } }, "Exemplos:"), e("br"),
                            e("span", { style: { fontSize: "11px" } }, "\"Quem é a personagem principal?\""), e("br"),
                            e("span", { style: { fontSize: "11px" } }, "\"Esta frase faz sentido em contexto?\""), e("br"),
                            e("span", { style: { fontSize: "11px" } }, "\"Qual o tom desta cena?\"")
                        ) : null,

                        s.chatMessages.map(function (msg, i) {
                            var isUser = msg.role === "user";
                            return e("div", {
                                key: i,
                                style: {
                                    padding: "8px 11px", borderRadius: "10px", fontSize: "12px", lineHeight: "1.65",
                                    alignSelf: isUser ? "flex-end" : "flex-start",
                                    maxWidth: "88%",
                                    background: isUser ? PURPLE : CARD,
                                    color: isUser ? "#fff" : TEXT,
                                    border: isUser ? "none" : "1px solid " + BORDER,
                                    whiteSpace: "pre-wrap"
                                }
                            }, msg.content);
                        }),

                        s.chatLoading ? e("div", {
                            style: { padding: "8px 11px", background: CARD, border: "1px solid " + BORDER, borderRadius: "10px", color: MUTED, fontSize: "12px", alignSelf: "flex-start" }
                        }, "●●●") : null,

                        s.chatError ? e("div", {
                            style: { padding: "8px 10px", background: ERR_BG, color: ERR, borderRadius: "6px", fontSize: "11px" }
                        }, "⚠ " + s.chatError) : null
                    ),

                    // Input + enviar + limpar
                    e("div", { style: { display: "flex", gap: "6px", alignItems: "flex-end" } },
                        e("textarea", {
                            value: s.chatInput,
                            placeholder: "Pergunta sobre o mangá, personagens, tradução...",
                            onChange: function (ev) { props.onChatInput(ev.target.value); },
                            onKeyDown: props.onChatKey,
                            rows: 2,
                            style: { flex: 1, padding: "7px 10px", background: SURF, color: TEXT, border: "1px solid " + BORDER, borderRadius: "6px", fontSize: "12px", resize: "none", fontFamily: "inherit" }
                        }),
                        e("div", { style: { display: "flex", flexDirection: "column", gap: "4px" } },
                            e("button", {
                                onClick: props.onChatSend, disabled: s.chatLoading || !s.chatInput.trim(),
                                style: { padding: "7px 12px", background: s.chatLoading ? BORDER : PURPLE, color: "#fff", border: "none", borderRadius: "6px", cursor: "pointer", fontWeight: 700, fontSize: "13px" }
                            }, "→"),
                            s.chatMessages.length > 0 ? e("button", {
                                onClick: props.onClearChat,
                                style: { padding: "5px", background: "none", color: MUTED, border: "1px solid " + BORDER, borderRadius: "6px", cursor: "pointer", fontSize: "10px" }
                            }, "🗑") : null
                        )
                    )

                ) : null;

                // ── Root ──────────────────────────────────────────────
                return e("div", { style: { background: BG, color: TEXT, height: "100%", display: "flex", flexDirection: "column", fontFamily: "'Inter', sans-serif", fontSize: "13px" } },

                    // Header
                    e("div", { style: { padding: "11px 14px", borderBottom: "1px solid " + BORDER, display: "flex", alignItems: "center", gap: "8px", flexShrink: 0 } },
                        e("span", { style: { fontSize: "15px" } }, "🌐"),
                        e("span", { style: { fontWeight: 700, fontSize: "13px" } }, "Tradutor de Mangá"),
                        e("span", { style: { marginLeft: "auto", fontSize: "10px", color: MUTED } }, "Ollama local")
                    ),

                    // Tabs
                    e("div", { style: { display: "flex", flexShrink: 0 } },
                        tabBtn("translate", "🌐 Traduzir", s.tab === "translate"),
                        tabBtn("chat",      "💬 Chat IA",  s.tab === "chat")
                    ),

                    // Conteúdo
